features.snippet:
interface iface (input logic clk);
    logic valid;
    modport sink (input clk, input valid);
endinterface

module leaf (iface.sink S);
endmodule

module middle (iface.sink S);
    leaf u (.S(S));
endmodule

module top #(parameter bit P = 0) (input logic clk);
    generate
        if (P) begin : g
            iface s (.clk(clk));
        end else begin : g
            iface s (.clk(clk));
        end
    endgenerate
    middle u (.S(g.s));
endmodule
